  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // LOGIKA AUTO-LOCK (5 MIN)
  const resetActivityTimer = useCallback(() => {
    if (!isAuthenticated || !isUnlocked) return;
    if (activityTimerRef.current) clearTimeout(activityTimerRef.current);
    activityTimerRef.current = setTimeout(() => {
      setIsUnlocked(false);
      sessionStorage.removeItem('app_unlocked');
    }, 5 * 60 * 1000); // 5 minút
  }, [isAuthenticated, isUnlocked]);

  useEffect(() => {
    const events = ['mousedown', 'keydown', 'touchstart', 'scroll'];
    if (isAuthenticated && isUnlocked) {
      events.forEach(e => window.addEventListener(e, resetActivityTimer));
      resetActivityTimer();
    }
    return () => {
      events.forEach(e => window.removeEventListener(e, resetActivityTimer));
      if (activityTimerRef.current) clearTimeout(activityTimerRef.current);
    };
  }, [isAuthenticated, isUnlocked, resetActivityTimer]);

