      const timer = setTimeout(() => {
          if (!hasInitialData) setSyncTimeout(true);
      }, 5000);
      return () => clearTimeout(timer);
  }, [hasInitialData]);

  const isDataLoading = !hasInitialData && !syncTimeout;

