                    </div>
                    <button onClick={() => { if(window.confirm('Zmazať sektor?')) onDeleteMapSector(s.id); }} className="text-slate-600 hover:text-red-500 transition-all font-black px-2 text-xl ml-2">×</button>
                </div>
              </div>
