const SettingsTab: React.FC<SettingsTabProps> = (props) => {
  const { hasPermission, resolveName } = props;
  const { t, language } = useLanguage();

  const navTiles = useMemo(() => {
    const all = [
      { id: 'summary', label: language === 'sk' ? 'SÚHRN' : 'SUMMARY', icon: <Icons.Summary />, perm: 'perm_view_setup' },
      { id: 'users', label: t('sect_users_manage'), icon: <Icons.Users />, perm: 'perm_settings_users' },
      { id: 'parts', label: t('sect_parts'), icon: <Icons.Parts />, perm: 'perm_settings_parts' },
      { id: 'wp', label: t('sect_wp'), icon: <Icons.Workplaces />, perm: 'perm_settings_wp' },
      { id: 'bom', label: t('sect_bom'), icon: <Icons.BOM />, perm: 'perm_settings_bom' },
      { id: 'system', label: 'SYSTÉM', icon: <Icons.System />, perm: 'perm_settings_system' },
      { id: 'maint', label: 'ÚDRŽBA', icon: <Icons.Archive />, perm: 'perm_settings_maint' },
      { id: 'yearly', label: language === 'sk' ? 'UZÁVIERKA' : 'CLOSING', icon: <Icons.Yearly />, perm: 'perm_manage_roles' },
    ];
    return all.filter(tile => hasPermission(tile.perm));
  }, [language, t, hasPermission]);

  const [activeSubTab, setActiveSubTab] = useState<string | null>(navTiles[0]?.id || null);

  if (navTiles.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center py-20 text-slate-500 italic bg-slate-900/40 border border-slate-800 rounded-3xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
              {t('action_not_allowed')}
          </div>
      );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-fade-in px-4 md:px-0">
      <PartRequestsSection 
        partRequests={props.partRequests} 
        bomRequests={props.bomRequests}
        onApprovePartRequest={props.onApprovePartRequest}
        onRejectPartRequest={props.onRejectPartRequest}
        onApproveBOMRequest={props.onApproveBOMRequest}
        onRejectBOMRequest={props.onRejectBOMRequest}
        resolveName={resolveName}
      />

      <div className={`grid gap-3 mb-8 ${
          navTiles.length <= 4 ? 'grid-cols-2 md:grid-cols-4' : 'grid-cols-2 md:grid-cols-4 lg:grid-cols-8'
      }`}>
        {navTiles.map(tile => {
          const isActive = activeSubTab === tile.id;
          return (
            <button 
              key={tile.id} 
              onClick={() => setActiveSubTab(tile.id)}
              className={`flex flex-col items-center justify-center p-6 rounded-3xl border-2 transition-all duration-300 group relative ${
                isActive 
                ? 'bg-teal-500/10 border-teal-500 shadow-[0_0_20px_rgba(20,184,166,0.3)]' 
                : 'bg-slate-900/40 border-slate-800 hover:border-slate-700 hover:bg-slate-800/50'
              }`}
            >
              <div className={`mb-3 transition-transform group-hover:scale-110 ${isActive ? 'text-teal-400' : 'text-slate-600'}`}>
                {tile.icon}
              </div>
              <span className={`text-[10px] font-black uppercase tracking-widest text-center leading-tight ${isActive ? 'text-teal-400' : 'text-slate-500'}`}>
                {tile.label}
              </span>
            </button>
          );
        })}
      </div>

      <div className="animate-fade-in">
        {activeSubTab === 'summary' && (
          <SetupView 
            users={props.users}
            parts={props.parts}
            workplaces={props.workplaces}
            missingReasons={props.missingReasons}
            logisticsOperations={props.logisticsOperations || []}
            breakSchedules={props.breakSchedules}
            bomMap={props.bomMap}
            systemConfig={props.systemConfig}
          />
        )}
        {activeSubTab === 'users' && (
          <UserSection 
            users={props.users} 
            roles={props.roles} 
            onAddUser={props.onAddUser} 
            onUpdatePassword={props.onUpdatePassword} 
            onUpdateNickname={props.onUpdateNickname}
            onUpdateExportPermission={props.onUpdateExportPermission}
            onDeleteUser={props.onDeleteUser} 
          />
        )}
        {activeSubTab === 'parts' && (
          <PartsSection 
            parts={props.parts} 
            onAddPart={props.onAddPart} 
            onBatchAddParts={props.onBatchAddParts} 
            onDeletePart={props.onDeletePart} 
            onDeleteAllParts={props.onDeleteAllParts} 
          />
        )}
        {activeSubTab === 'wp' && (
          <WorkplaceSection 
            workplaces={props.workplaces} 
            logisticsOperations={props.logisticsOperations || []}
            onAddWorkplace={props.onAddWorkplace}
            onUpdateWorkplace={props.onUpdateWorkplace}
            onBatchAddWorkplaces={props.onBatchAddWorkplaces}
            onDeleteWorkplace={props.onDeleteWorkplace}
            onDeleteAllWorkplaces={props.onDeleteAllWorkplaces}
            onAddLogisticsOperation={props.onAddLogisticsOperation || (() => {})}
            onUpdateLogisticsOperation={props.onUpdateLogisticsOperation || (() => {})}
            onDeleteLogisticsOperation={props.onDeleteLogisticsOperation || (() => {})}
            mapSectors={props.mapSectors}
            onAddMapSector={props.onAddMapSector}
            onDeleteMapSector={props.onDeleteMapSector}
            onUpdateMapSector={props.onUpdateMapSector}
          />
        )}
        {activeSubTab === 'bom' && (
          <BOMSection 
            bomMap={props.bomMap} 
            onAddBOMItem={props.onAddBOMItem} 
            onBatchAddBOMItems={props.onBatchAddBOMItems} 
            onDeleteBOMItem={props.onDeleteBOMItem} 
            onDeleteAllBOMItems={props.onDeleteAllBOMItems} 
          />
        )}
        {activeSubTab === 'system' && (
          <SystemSection 
            missingReasons={props.missingReasons} 
            breakSchedules={props.breakSchedules} 
            onAddMissingReason={props.onAddMissingReason} 
            onDeleteMissingReason={props.onDeleteMissingReason} 
            onAddBreakSchedule={props.onAddBreakSchedule} 
            onDeleteBreakSchedule={props.onDeleteBreakSchedule} 
            onUpdateAdminKey={props.onUpdateAdminKey}
            isAdminLockEnabled={props.systemConfig.adminLockEnabled || false}
            onToggleAdminLock={props.onToggleAdminLock}
            systemConfig={props.systemConfig}
            onUpdateSystemConfig={props.onUpdateSystemConfig}
          />
        )}
        {activeSubTab === 'maint' && (
          <MaintenanceSection 
            systemConfig={props.systemConfig} 
            onUpdateSystemConfig={props.onUpdateSystemConfig} 
            onArchiveTasks={props.onArchiveTasks} 
            onDailyClosing={props.onDailyClosing}
            onWeeklyClosing={props.onWeeklyClosing}
            onGetDocCount={props.onGetDocCount}
            onPurgeOldTasks={props.onPurgeOldTasks}
            onExportTasksJSON={props.onExportTasksJSON}
          />
        )}
        {activeSubTab === 'yearly' && (
          <YearlyClosing resolveName={resolveName} />
        )}
      </div>
    </div>
  );
};

export default SettingsTab;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { useAppSecurity } from './hooks/useAppSecurity';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc,
  deleteField,
  increment,
  getCountFromServer,
  getDoc
} from 'firebase/firestore';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
  nickname?: string;
  canExportAnalytics?: boolean;
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
  description?: string;
  coordX?: number;
  coordY?: number;
}

export interface MapSector {
  id: string;
  name: string;
  coordX: number;
  coordY: number;
  color?: string;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean; 
  blockedBy?: string | null; 
  isManualBlocked?: boolean; 
  inventoryHistory?: InventorySession[];
  isLogistics?: boolean; 
  isProduction?: boolean;
  isAuditInProgress?: boolean;
  auditBy?: string | null;
  auditFinalBadge?: string | null;
  auditedBy?: string | null;
  auditedAt?: number | null;
  auditResult?: 'OK' | 'NOK' | null;
  auditNote?: string | null;
  expireAt?: number;
  searchExhausted?: boolean;
  searchedBy?: string | null;
  pickedFromSectorId?: string;
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    targetUser: string; 
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMComponent {
    child: string;
    consumption: number;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

export interface SystemConfig {
    maintenanceMode: boolean;
    maintenanceStart?: string;
    maintenanceEnd?: string;
    allowedIPs: string[];
    ipCheckEnabled: boolean;
    adminKey?: string;
    adminLockEnabled?: boolean;
    mapOriginX?: number;
    mapOriginY?: number;
}

const colorMap: Record<string, string> = {
  blue: 'bg-blue-600 border-blue-500 hover:bg-blue-500',
  green: 'bg-green-600 border-green-500 hover:bg-green-500',
  orange: 'bg-orange-600 border-orange-500 hover:bg-orange-500',
  teal: 'bg-teal-600 border-teal-500 hover:bg-teal-500',
  pink: 'bg-pink-600 border-pink-500 hover:bg-pink-500',
  red: 'bg-red-600 border-red-500 hover:bg-red-500',
  slate: 'bg-slate-900 border-slate-700 hover:bg-slate-800'
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');

  // Custom Hook pre bezpečnosť a config
  const { 
    isUnlocked, 
    setIsUnlocked, 
    systemConfig, 
    handleUnlockAttempt, 
    handleUpdateAdminKey,
    handleUpdateSystemConfig
  } = useAppSecurity(currentUserRole, isAuthenticated);

  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]);

  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});

  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [dbLoadWarning, setDbLoadWarning] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Stavy pre modálne okno výberu sektora
  const [showSectorModal, setShowSectorModal] = useState(false);
  const [finishingTaskId, setFinishingTaskId] = useState<string | null>(null);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const handleLogout = () => { 
    setIsAuthenticated(false); 
    setIsUnlocked(false);
    setCurrentUser(''); 
    setCurrentUserRole('USER'); 
    localStorage.removeItem('app_user'); 
    localStorage.removeItem('app_role'); 
    sessionStorage.removeItem('app_unlocked');
  };

  useEffect(() => {
      if (isAuthenticated && currentUserRole !== 'ADMIN') {
          const now = new Date();
          const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
          const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                         currentISO >= systemConfig.maintenanceStart && 
                                         currentISO <= systemConfig.maintenanceEnd;
          if (systemConfig.maintenanceMode || isScheduledMaintenance) {
              handleLogout();
              alert('Systém prešiel do servisného módu. Boli ste odhlásení.');
          }
      }
  }, [systemConfig, isAuthenticated, currentUserRole]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const q = query(collection(db, 'tasks'), limit(500)); 
    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      return () => { unsubUsers(); unsubRoles(); unsubPerms(); };
  }, []);

  useEffect(() => {
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, string> = {};
          raw.forEach((item: any) => {
              if (item.p) cleanMap[item.p] = item.d || '';
          });
          setPartsMap(cleanMap);
      } else {
          setDoc(doc(db, 'settings', 'parts'), { data: [] });
      }
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, BOMComponent[]> = {};
          raw.forEach((item: any) => {
              if (item.parent && item.child) {
                  if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                  cleanMap[item.parent].push({ child: item.child, consumption: item.q || 0 });
              }
          });
          setBomMap(cleanMap);
      } else {
          setDoc(doc(db, 'settings', 'bom'), { data: [] });
      }
    });
    return () => { unsubParts(); unsubBOM(); };
  }, []);

  useEffect(() => { return onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'break_schedules')), s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);

  useEffect(() => { 
      return onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), async (s) => {
          if (s.empty && !s.metadata.fromCache) {
               const defaults = ['VYKLÁDKA', 'NAKLÁDKA', 'ZASKLADNENIE', 'INTERNÝ PRESUN'];
               const batch = writeBatch(db);
               defaults.forEach(op => batch.set(doc(collection(db, 'logistics_operations')), { value: op, standardTime: 0 }));
               await batch.commit();
          } else {
              const ops = s.docs.map(d => ({id:d.id, value:d.data().value, standardTime: d.data().standardTime} as DBItem));
              setLogisticsOperations(ops);
          }
      }); 
  }, []);

  useEffect(() => { 
      return onSnapshot(query(collection(db, 'map_sectors'), orderBy('name')), (s) => {
          setMapSectors(s.docs.map(d => ({ id: d.id, ...d.data() } as MapSector)));
      }); 
  }, []);

  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);

  useEffect(() => { 
      if (!isAuthenticated || !currentUser) return;
      const q = query(collection(db, 'notifications'), where('targetUser', '==', currentUser)); 
      return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); 
  }, [isAuthenticated, currentUser]);

  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  const handleLogin = (u: string, r: any) => { 
    setIsAuthenticated(true); 
    setCurrentUser(u); 
    setCurrentUserRole(r); 
    localStorage.setItem('app_user', u); 
    localStorage.setItem('app_role', r); 
    if (r !== 'ADMIN' || !systemConfig.adminLockEnabled) {
      setIsUnlocked(true);
      sessionStorage.setItem('app_unlocked', 'true');
    }
  };

  const handleAddUser = async (u: UserData) => { await addDoc(collection(db, 'users'), { ...u, canExportAnalytics: u.canExportAnalytics || false }); };
  const handleUpdatePassword = async (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {password: p}); } };
  const handleUpdateNickname = async (u: string, n: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {nickname: n}); } };
  const handleUpdateExportPermission = async (u: string, canExport: boolean) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {canExportAnalytics: canExport}); } };
  const handleUpdateUserRole = async (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {role: r}); } };
  const handleDeleteUser = async (u: string) => { const user = users.find(us => us.username === u); if(user) { await deleteDoc(doc(db,'users', user.id!)); } };

  const handleAddPart = async (v: string, desc?: string) => { 
    const updatedMap = { ...partsMap, [v.trim()]: desc || '' };
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleBatchAddParts = async (vs: string[]) => { 
    const updatedMap = { ...partsMap };
    vs.forEach(line => {
      const [val, desc] = line.split(';');
      if (val) updatedMap[val.trim()] = desc ? desc.trim() : '';
    });
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleDeletePart = async (partValue: string) => { 
    const updatedMap = { ...partsMap };
    delete updatedMap[partValue];
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleDeleteAllParts = async () => { 
    await setDoc(doc(db, 'settings', 'parts'), { data: [] }); 
  };

  const handleAddBOMItem = async (p: string, c: string, q: number) => { 
    const updatedMap = { ...bomMap };
    const current = updatedMap[p] || [];
    updatedMap[p] = [...current.filter(item => item.child !== c), { child: c, consumption: Number(q.toFixed(5)) }];
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([parent, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleBatchAddBOMItems = async (vs: string[]) => { 
    const updatedMap = { ...bomMap };
    vs.forEach(l => {
      const [p, c, q] = l.split(';');
      if (p && c && q) {
        const parent = p.trim();
        if (!updatedMap[parent]) updatedMap[parent] = [];
        const sanitizedQty = Number(parseFloat(q.trim().replace(',', '.')).toFixed(5));
        updatedMap[parent] = [...updatedMap[parent].filter(x => x.child !== c.trim()), { child: c.trim(), consumption: sanitizedQty }];
      }
    });
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([parent, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleDeleteBOMItem = async (parent: string, child: string) => { 
    const updatedMap = { ...bomMap };
    if (updatedMap[parent]) {
        updatedMap[parent] = updatedMap[parent].filter(item => item.child !== child);
        if (updatedMap[parent].length === 0) delete updatedMap[parent];
    }
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([pKey, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent: pKey, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleDeleteAllBOMItems = async () => { 
    await setDoc(doc(db, 'settings', 'bom'), { data: [] }); 
  };

  const handleAddWorkplace = async (v: string, t?: number, x?: number, y?: number) => { 
    await addDoc(collection(db, 'workplaces'), { value: v, standardTime: t || 0, coordX: x || 0, coordY: y || 0 }); 
  };
  const handleUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => { 
    await updateDoc(doc(db, 'workplaces', id), updates); 
  };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0, coordX: 0, coordY: 0})}); await b.commit(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); };
  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); };
  const handleAddLogisticsOperation = async (v: string, t?: number) => { await addDoc(collection(db,'logistics_operations'), {value:v}); };
  const handleUpdateLogisticsOperation = async (id: string, t: number) => { await updateDoc(doc(db, 'logistics_operations', id), { standardTime: t }); };
  const handleDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db,'logistics_operations',id)); };

  const handleAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color: color || 'slate' }); };
  const handleDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };
  const handleUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };

  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));
  const handleAddBreakSchedule = async (s:string, e:string) => { await addDoc(collection(db,'break_schedules'), {start:s, end:e}); };
  const handleDeleteBreakSchedule = async (id: string) => { await deleteDoc(doc(db,'break_schedules',id)); };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));
  const handleAddRole = async (n:string) => { const nameUpper = n.toUpperCase(); if (roles.some(r => r.name === nameUpper)) { alert("Rola s týmto názvom už existuje!"); return; } await addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false}); };
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) await addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) await deleteDoc(doc(db,'permissions',p.id)); } };
  const handleVerifyAdminPassword = (password: string) => { return users.some(u => u.role === 'ADMIN' && u.password === password); };
  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics: boolean = false, note?: string) => {
    let finalUnit = unit;
    const description = partsMap[pn];
    if (description) {
        if (description.includes('S0001S')) finalUnit = 'pcs';
        else if (description.includes('S0002S')) finalUnit = 'boxes';
        else if (description.includes('S0003S')) finalUnit = 'pallet';
    }
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(finalUnit === 'boxes') fQty = `${qty} box`; 
    if(finalUnit === 'pallet') fQty = `${qty} pal`;
    let text = `${formattedDate} / ${pn}`; 
    if (wp) text += ` / ${wp}`; 
    if (fQty) text += ` / Počet: ${fQty}`;
    if (note) text += ` / Pozn: ${note}`;
    let finalStandardTime = 0;
    if (!isLogistics) {
        const wpObj = workplaces.find(w => w.value === wp);
        finalStandardTime = wpObj?.standardTime || 0;
        if (finalUnit === 'pallet' && qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) finalStandardTime = Math.round(finalStandardTime * numericQty);
        }
    } else {
        const opObj = logisticsOperations.find(op => op.value === wp); 
        finalStandardTime = opObj?.standardTime || 0;
        if (qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) finalStandardTime = Math.round(finalStandardTime * numericQty);
        }
    }
    const isInventoryTask = pn === "Počítanie zásob";
    const now = Date.now();
    await addDoc(collection(db, 'tasks'), { text, partNumber: pn, workplace: wp, quantity: qty, quantityUnit: finalUnit, standardTime: finalStandardTime, isDone:false, priority:prio, createdAt:now, createdBy:currentUser, isLogistics, isProduction: !isLogistics, isInProgress: isInventoryTask, inProgressBy: isInventoryTask ? currentUser : null, startedAt: isInventoryTask ? now : null, note: note || null, expireAt: now + (90 * 24 * 60 * 60 * 1000) });
  };

  const handleUpdateTask = async (id: string, updates: Partial<Task>) => { await updateDoc(doc(db, 'tasks', id), updates); };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        if (!t.isDone) {
            // Ak ideme dokončiť, otvoríme modal výberu sektora (Fáza 1)
            setFinishingTaskId(id);
            setShowSectorModal(true);
            return;
        }
        // Undo logika (ak sa úloha "odškrtáva")
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false, isAuditInProgress: false, auditBy: null, pickedFromSectorId: deleteField() });
    }
  };

  const confirmTaskCompletion = async (sectorId: string) => {
    if (!finishingTaskId) return;
    const id = finishingTaskId;
    await updateDoc(doc(db, 'tasks', id), { 
        isDone: true, 
        status: 'completed', 
        completionTime: new Date().toLocaleTimeString('sk-SK'), 
        completedBy: currentUser, 
        completedAt: Date.now(), 
        isInProgress: false, 
        inProgressBy: null, 
        isBlocked: false, 
        isManualBlocked: false, 
        isAuditInProgress: false, 
        auditBy: null,
        pickedFromSectorId: sectorId
    });
    setShowSectorModal(false);
    setFinishingTaskId(null);
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false, isAuditInProgress: false, auditBy: null });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));
  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null, 
              isInProgress: false, 
              inProgressBy: null, 
              isBlocked: false, 
              blockedBy: null, 
              searchedBy: isMissing ? (t.searchedBy || null) : null,
              isManualBlocked: false, 
              isAuditInProgress: false, 
              auditBy: null 
          });
          if (isMissing && t.createdBy && t.createdBy !== currentUser) {
              await addDoc(collection(db, 'notifications'), { 
                  partNumber: t.partNumber || 'Unknown', 
                  reason: reason || 'Iné', 
                  reportedBy: currentUser, 
                  targetUser: t.createdBy, 
                  timestamp: Date.now() 
              });
          }
      } 
  };
  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));
  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          const u = users.find(x => x.username === currentUser);
          const nickname = u?.nickname || currentUser;
          updateDoc(doc(db,'tasks',id), { 
              isBlocked, 
              blockedBy: isBlocked ? currentUser : null, 
              searchedBy: isBlocked ? nickname : (t.searchedBy || null),
              inventoryHistory:hist 
          });
      }
  };
  const handleToggleManualBlock = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) {
          const newState = !t.isManualBlocked;
          await updateDoc(doc(db, 'tasks', id), { isManualBlocked: newState, createdAt: !newState ? Date.now() : t.createdAt, isInProgress: false, inProgressBy: null });
      }
  };
  const handleExhaustSearch = async (id: string) => {
      await updateDoc(doc(db, 'tasks', id), { searchExhausted: true, isBlocked: false, blockedBy: null });
  };
  const handleStartAudit = async (id: string) => { 
      const u = users.find(x => x.username === currentUser);
      const name = (u?.nickname || currentUser);
      await updateDoc(doc(db, 'tasks', id), { isAuditInProgress: true, auditBy: name }); 
  };
  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
      const t = tasks.find(x => x.id === id);
      if (!t) return;
      const u = users.find(x => x.username === currentUser);
      const displayName = (u?.nickname || currentUser).toUpperCase();
      const statusLabel = result === 'found' ? 'OK' : 'CHÝBA';
      const badgeText = `AUDIT ${statusLabel}: ${note} (${displayName})`;
      const auditData = { 
          auditedBy: currentUser, 
          auditedAt: Date.now(), 
          auditResult: result === 'found' ? 'OK' : 'NOK', 
          auditNote: note, 
          isAuditInProgress: false, 
          auditBy: null, 
          auditFinalBadge: badgeText 
      };
      if (result === 'found') {
          await updateDoc(doc(db, 'tasks', id), { ...auditData, isMissing: false });
      } else {
          await updateDoc(doc(db, 'tasks', id), { 
              ...auditData, 
              isDone: true, 
              status: 'completed', 
              completionTime: new Date().toLocaleTimeString('sk-SK'), 
              completedBy: currentUser, 
              completedAt: Date.now() 
          });
      }
      if (t.createdBy && t.createdBy !== currentUser) {
          await addDoc(collection(db, 'notifications'), { partNumber: t.partNumber || 'N/A', reason: `AUDIT DOKONČENÝ (${statusLabel}): ${note}`, reportedBy: currentUser, targetUser: t.createdBy, timestamp: Date.now() });
      }
  };
  const handleDailyClosing = async () => {
      const q = query(collection(db, 'tasks'), where('isDone', '==', true));
      const s = await getDocs(q);
      if (s.empty) return { success: true, count: 0 };
      const batch = writeBatch(db);
      s.docs.forEach(d => {
          batch.set(doc(collection(db, 'archive_drafts')), { ...d.data(), archivedAt: Date.now() });
          batch.delete(d.ref);
      });
      await batch.commit();
      return { success: true, count: s.size };
  };
  const handleWeeklyClosing = async () => {
      const s = await getDocs(collection(db, 'archive_drafts'));
      if (s.empty) return { success: true, count: 0 };
      const now = new Date();
      const year = now.getFullYear();
      const firstDayOfYear = new Date(year, 0, 1);
      const pastDaysOfYear = (now.getTime() - firstDayOfYear.getTime()) / 86400000;
      const weekNum = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7);
      const sanonName = `sanon_${year}_${weekNum}`;
      const batch = writeBatch(db);
      s.docs.forEach(d => {
          batch.set(doc(collection(db, sanonName)), d.data());
          batch.delete(d.ref);
      });
      await batch.commit();
      return { success: true, count: s.size, sanon: sanonName };
  };
  const handleArchiveTasks = async () => { return await handleDailyClosing(); };
  const fetchArchivedTasks = async () => (await getDocs(query(collection(db,'archive_drafts'), limit(500)))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  const handleGetDocCount = useCallback(async () => {
      const snap = await getCountFromServer(collection(db, 'tasks'));
      return snap.data().count;
  }, []);
  const handlePurgeOldTasks = useCallback(async () => {
      const ninetyDaysAgo = Date.now() - (90 * 24 * 60 * 60 * 1000);
      const q = query(collection(db, 'tasks'), where('createdAt', '<', ninetyDaysAgo), limit(500));
      const snap = await getDocs(q);
      if (snap.empty) return 0;
      const batch = writeBatch(db);
      snap.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
      return snap.size;
  }, []);
  const handleExportTasksJSON = useCallback(async () => {
      const snap = await getDocs(query(collection(db, 'tasks'), limit(1000)));
      const data = snap.docs.map(d => ({ id: d.id, ...d.data() }));
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `backup_tasks_${new Date().toISOString().slice(0,10)}.json`;
      a.click();
  }, []);
  const partsArray = Object.entries(partsMap).map(([value, description]) => ({ id: value, value, description }));

  const LockScreen = ({ onUnlock }: { onUnlock: (key: string) => void }) => {
    const [input, setInput] = useState('');
    return (
      <div className="fixed inset-0 z-[10000] bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-gray-800 border-2 border-slate-700 p-10 rounded-[2rem] shadow-2xl w-full max-w-sm text-center">
          <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center mx-auto mb-8 border border-blue-500/50">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-10 h-10 text-[#4169E1]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">SYSTÉM UZAMKNUTÝ</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-8">ZADAJTE BEZPEČNOSTNÝ KĽÚČ</p>
          <input 
            type="password" 
            autoFocus
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && onUnlock(input)}
            placeholder="••••"
            className="w-full h-16 bg-slate-900 border-2 border-slate-700 rounded-xl text-center text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all mb-6"
          />
          <button 
            onClick={() => onUnlock(input)}
            className="w-full py-4 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black rounded-xl uppercase tracking-widest text-xs border-2 border-blue-500 shadow-xl transition-all active:scale-95"
          >
            ODOMKNÚŤ SYSTÉM
          </button>
        </div>
      </div>
    );
  };

  const handleToggleAdminLock = (val: boolean) => {
    handleUpdateSystemConfig({ adminLockEnabled: val });
  };

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} systemConfig={systemConfig} />
      ) : (currentUserRole === 'ADMIN' && systemConfig.adminLockEnabled && !isUnlocked) ? (
        <LockScreen onUnlock={handleUnlockAttempt} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          onDeleteTask={handleDeleteTask}
          onUpdateTask={handleUpdateTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onToggleManualBlock={handleToggleManualBlock}
          onExhaustSearch={handleExhaustSearch}
          onStartAudit={handleStartAudit} onFinishAudit={handleFinishAudit}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateNickname={handleUpdateNickname} onUpdateExportPermission={handleUpdateExportPermission} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={partsArray} workplaces={workplaces} missingReasons={missingReasons} logisticsOperations={logisticsOperations}
          mapSectors={mapSectors} onAddMapSector={handleAddMapSector} onDeleteMapSector={handleDeleteMapSector} onUpdateMapSector={handleUpdateMapSector}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onUpdateWorkplace={handleUpdateWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          onAddLogisticsOperation={handleAddLogisticsOperation} onUpdateLogisticsOperation={handleUpdateLogisticsOperation} onDeleteLogisticsOperation={handleDeleteLogisticsOperation}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onDailyClosing={handleDailyClosing}
          onWeeklyClosing={handleWeeklyClosing}
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          onGetDocCount={handleGetDocCount}
          onPurgeOldTasks={handlePurgeOldTasks}
          onExportTasksJSON={handleExportTasksJSON}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomMap={bomMap} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest} roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          onVerifyAdminPassword={handleVerifyAdminPassword}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
          systemConfig={systemConfig} onUpdateSystemConfig={handleUpdateSystemConfig}
          dbLoadWarning={dbLoadWarning} 
          onUpdateAdminKey={handleUpdateAdminKey}
          onToggleAdminLock={handleToggleAdminLock}
        />
      )}

      {/* MODAL PRE VÝBER ZDROJA (FÁZA 1) */}
      {showSectorModal && (
        <div className="fixed inset-0 z-[11000] bg-black/90 backdrop-blur-lg flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-gray-800 border-2 border-teal-500 p-8 rounded-[2rem] shadow-2xl w-[95%] md:max-w-4xl text-center ring-4 ring-teal-500/10">
            <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-10 leading-tight">ODKIAL SI BRAL TOVAR?<br/><span className="text-teal-400 text-sm tracking-widest">(VYBER MIESTO)</span></h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
              {mapSectors.length > 0 ? mapSectors.map(s => (
                <button 
                  key={s.id} 
                  onClick={() => confirmTaskCompletion(s.id)}
                  className={`py-8 border-2 text-white font-black rounded-2xl uppercase tracking-normal text-2xl transition-all active:scale-95 shadow-xl ${s.color ? colorMap[s.color] : colorMap.slate}`}
                >
                  {s.name}
                </button>
              )) : (
                <div className="col-span-2 py-4 text-slate-500 italic text-lg">Žiadne sektory nie sú definované v nastaveniach.</div>
              )}
            </div>
            <button 
              onClick={() => { setShowSectorModal(false); setFinishingTaskId(null); }}
              className="mt-6 text-slate-500 font-black uppercase tracking-widest text-sm hover:text-slate-300 transition-colors"
            >
              SPÄŤ NA ZOZNAM
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import TaskList from './tabs/TaskList';
import SettingsTab from './settings/SettingsTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import MissingItemsTab from './tabs/MissingItemsTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import InventoryTab from './tabs/InventoryTab';
import PermissionsTab from './tabs/PermissionsTab';
import BOMScreen from './tabs/BOMScreen';
import ProductionEntry from './tabs/ProductionEntry';
import PartCatalogTab from './tabs/PartCatalogTab';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import { UserData, DBItem, PartRequest, BreakSchedule, SystemBreak, BOMComponent, BOMRequest, Role, Permission, Task, Notification as AppNotification, PriorityLevel, SystemConfig, MapSector } from '../App';
import { useLanguage } from './LanguageContext';

declare var XLSX: any;

interface PartSearchScreenProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  tasks: Task[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, note?: string) => void; 
  onUpdateTask: (id: string, updates: Partial<Task>) => void;
  onToggleTask: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void; 
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void; 
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onDeleteMissingItem: (id: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onReleaseTask: (id: string) => void;
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  onDailyClosing: () => Promise<{ success: boolean; count: number }>;
  onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon?: string }>;
  onFetchArchivedTasks: () => Promise<Task[]>;
  onStartAudit: (id: string) => void;
  onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => void;
  onGetDocCount: () => Promise<number>;
  onPurgeOldTasks: () => Promise<number>;
  onExportTasksJSON: () => Promise<void>;
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateNickname: (username: string, newNick: string) => void;
  onUpdateExportPermission: (username: string, canExport: boolean) => void;
  onUpdateUserRole: (username: string, newRole: any) => void;
  onDeleteUser: (username: string) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllAllWorkplaces?: () => void; 
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number) => void; 
  onUpdateLogisticsOperation: (id: string, time: number) => void;
  onDeleteLogisticsOperation: (id: string) => void;
  mapSectors: MapSector[];
  onAddMapSector: (name: string, x: number, y: number) => void;
  onDeleteMapSector: (id: string) => void;
  onUpdateMapSector: (id: string, updates: Partial<MapSector>) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomMap: Record<string, BOMComponent[]>;
  bomRequests: BOMRequest[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (parent: string, child: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  onVerifyAdminPassword: (password: string) => boolean;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
}

const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const ClockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleBlock, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks, onDailyClosing, onWeeklyClosing,
    breakSchedules,
    bomMap, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning, onGetDocCount, onPurgeOldTasks, onExportTasksJSON
  } = props;

  const { t, language, setLanguage } = useLanguage();

  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');
  const [selectedPart, setSelectedPart] = useState<DBItem | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog'>('entry');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const [auditStartTask, setAuditStartTask] = useState<Task | null>(null);
  const [auditFinishTask, setAuditFinishTask] = useState<Task | null>(null);
  const [auditNote, setAuditNote] = useState('');

  const [searchConfirmTask, setSearchConfirmTask] = useState<Task | null>(null);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart?.description) return null;
    const desc = selectedPart.description;
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode]);

  useEffect(() => {
    if (unitLock) {
      setQuantityUnit(unitLock);
    }
  }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const unfinishedTasksCount = tasks.filter(t => !t.isDone).length;
  const pendingRequestsCount = props.partRequests.length + props.bomRequests.length;

  const partNumbersList = useMemo(() => parts.map(p => p.value), [parts]);

  const [hasInitialData, setHasInitialData] = useState(false);
  const [syncTimeout, setSyncTimeout] = useState(false);

  useEffect(() => {
    if (parts.length > 0) {
        setHasInitialData(true);
    }
  }, [parts.length]);

  useEffect(() => {
      const timer = setTimeout(() => {
          if (!hasInitialData) setSyncTimeout(true);
      }, 5000);
      return () => clearTimeout(timer);
  }, [hasInitialData]);

  const isDataLoading = !hasInitialData && !syncTimeout;

  const logisticsOperationsList = useMemo(() => {
      if (props.logisticsOperations && props.logisticsOperations.length > 0) {
          return props.logisticsOperations;
      }
      return [
          { id: 'op_unloading', value: t('op_unloading') },
          { id: 'op_loading', value: t('op_loading') },
          { id: 'op_putaway', value: t('op_putaway') },
          { id: 'op_move', value: t('op_move') }
      ];
  }, [props.logisticsOperations, t]);

  useEffect(() => {
      if (entryMode === 'logistics') {
          setQuantityUnit('pallet');
      } else {
          setQuantityUnit('pcs');
      }
  }, [entryMode]);

  const handleSendToTasks = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) {
            alert(t('fill_all_fields')); 
            return;
        }
        onAddTask(selectedPart.value, selectedWorkplace, quantity, quantityUnit, priority, false);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) {
            alert(t('fill_all_fields'));
            return;
        }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate);
    }

    setSelectedPart(null);
    setSelectedWorkplace(null);
    setLogisticsRef('');
    setLogisticsOp('');
    setLogisticsPlate('');
    setQuantity('');
    if (entryMode === 'logistics') { setQuantityUnit('pallet'); } else { setQuantityUnit('pcs'); }
    setPriority('NORMAL'); 
    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const handleAuditClick = (task: Task) => {
      if (task.isAuditInProgress) { setAuditFinishTask(task); setAuditNote(''); } else { setAuditStartTask(task); }
  };

  const handleConfirmStartAudit = () => { if (auditStartTask) { props.onStartAudit(auditStartTask.id); setAuditStartTask(null); } };
  const handleConfirmFinishAudit = (result: 'found' | 'missing', note: string) => { if (auditFinishTask && note.trim()) { props.onFinishAudit(auditFinishTask.id, result, note.trim()); setAuditFinishTask(null); } else { alert(t('fill_all_fields')); } };

  const handleSearchIconClick = (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const u = users.find(x => x.username === currentUser);
      const nickname = u?.nickname || currentUser;
      if (task.isBlocked) {
          onUpdateTask(id, { searchedBy: nickname });
          setSearchConfirmTask(task);
      } else {
          onToggleBlock(id);
      }
  };

  const handleConfirmFoundItem = (found: boolean) => {
      if (!searchConfirmTask) return;
      if (found) {
          onToggleMissing(searchConfirmTask.id);
      } else {
          onExhaustSearch(searchConfirmTask.id);
      }
      setSearchConfirmTask(null);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      {notifications.length > 0 && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4">
              <div className="bg-gray-800 rounded-2xl max-w-2xl w-full p-8 shadow-2xl border border-gray-700 animate-fade-in">
                  <div className="flex items-center justify-between mb-6 border-b border-gray-700 pb-4">
                      <h3 className="text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('alert_missing_title')}</h3>
                      <span className="bg-teal-500/20 text-teal-400 px-3 py-1 rounded-full text-xs font-bold">{notifications.length}</span>
                  </div>
                  <div className="space-y-4 max-h-[60vh] overflow-y-auto custom-scrollbar pr-2">
                      {notifications.map(notif => {
                          const isAudit = notif.reason.toUpperCase().includes('AUDIT');
                          const itemBgClass = isAudit ? "bg-amber-900/20 border-amber-800/40" : "bg-red-900/20 border-red-800/40";
                          const iconColorClass = isAudit ? "text-amber-400" : "text-red-400";
                          return (
                              <div key={notif.id} className={`${itemBgClass} border p-5 rounded-xl flex items-center justify-between gap-6 transition-all hover:bg-opacity-30`}>
                                  <div className="flex-grow min-w-0">
                                      <div className="flex items-center gap-3 mb-1">
                                          <div className={`w-2 h-2 rounded-full ${isAudit ? 'bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.6)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'}`}></div>
                                          <p className="font-mono font-black text-2xl text-white uppercase truncate">{notif.partNumber}</p>
                                      </div>
                                      <p className="text-lg text-gray-200 font-medium leading-tight mb-2">{notif.reason}</p>
                                      <div className="flex items-center gap-4 text-sm text-gray-500 font-bold uppercase tracking-wide">
                                          <span className={iconColorClass + " truncate max-w-[120px]"}>{resolveName(notif.reportedBy)}</span>
                                          <span className="opacity-50">•</span>
                                          <span>{new Date(notif.timestamp).toLocaleString('sk-SK', {hour:'2-digit', minute:'2-digit', day:'2-digit', month:'2-digit'})}</span>
                                      </div>
                                  </div>
                                  <button onClick={() => props.onClearNotification(notif.id)} className="flex-shrink-0 bg-gray-900/50 text-gray-400 hover:text-white p-3 rounded-xl hover:bg-gray-700 transition-all active:scale-90">
                                      <CheckCircleIcon className="w-8 h-8" />
                                  </button>
                              </div>
                          );
                      })}
                  </div>
                  <div className="mt-8 flex gap-4">
                      <button onClick={() => notifications.forEach(n => props.onClearNotification(n.id))} className="flex-1 py-4 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-black text-lg shadow-xl transition-all active:scale-[0.98] uppercase tracking-widest">{t('alert_btn_ok')}</button>
                  </div>
              </div>
          </div>
      )}

      {props.isBreakActive && (
        <div className="w-full px-2 sm:px-4 pt-2 z-50 bg-gray-900">
            <div className="w-full bg-red-600 text-white py-5 rounded-xl shadow-[0_0_20px_rgba(220,38,38,0.6)] flex items-center justify-center gap-4 animate-pulse border-2 border-red-400">
                <ClockIcon className="w-10 h-10 flex-shrink-0" />
                <span className="font-black text-2xl sm:text-3xl uppercase tracking-[0.2em] length-none text-center">PREBIEHA PRESTÁVKA</span>
            </div>
        </div>
      )}

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={isFullscreen} onToggleFullscreen={handleToggleFullscreen} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} />

      {isDataLoading && activeTab === 'entry' ? (
          <div className="flex-grow flex items-center justify-center bg-gray-900">
              <div className="text-center space-y-6">
                  <div className="inline-block w-14 h-14 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="text-teal-400 font-black animate-pulse uppercase tracking-[0.2em] text-base">Synchronizujem databázu dielov...</p>
                  <p className="text-gray-600 text-sm">Pokúšam sa nadviazať spojenie so serverom.</p>
              </div>
          </div>
      ) : (
          <>
            <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: unfinishedTasksCount, pendingRequests: pendingRequestsCount }} />

            <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
                <div className="max-w-7xl mx-auto w-full h-full">
                {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                    <ProductionEntry 
                        mode={entryMode} 
                        setMode={setEntryMode} 
                        selectedPart={selectedPart} 
                        setSelectedPart={setSelectedPart} 
                        selectedWorkplace={selectedWorkplace} 
                        setSelectedWorkplace={setSelectedWorkplace} 
                        logisticsRef={logisticsRef} 
                        setLogisticsRef={setLogisticsRef} 
                        logisticsPlate={logisticsPlate} 
                        setLogisticsPlate={setLogisticsPlate} 
                        logisticsOp={logisticsOp} 
                        setLogisticsOp={setLogisticsOp} 
                        quantity={quantity} 
                        setQuantity={setQuantity} 
                        quantityUnit={quantityUnit} 
                        setQuantityUnit={setQuantityUnit} 
                        priority={priority} 
                        setPriority={setPriority} 
                        parts={parts} 
                        workplaces={workplaces} 
                        logisticsOperationsList={logisticsOperationsList} 
                        t={t} 
                        language={language} 
                        hasPermission={hasPermission} 
                        handleAdd={handleSendToTasks} 
                        onRequestPart={props.onRequestPart}
                        isUnitLocked={!!unitLock} 
                    />
                )}
                {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                    <PartCatalogTab 
                        parts={props.parts} 
                        onSelectPart={(p) => {
                          setSelectedPart(p);
                          setActiveTab('entry');
                        }} 
                    />
                )}
                {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                    <div className="animate-fade-in pb-20">
                    <div className="mb-6 flex justify-center">
                        <input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base" placeholder={t('task_search_placeholder')} />
                    </div>
                    <TaskList 
                        currentUser={currentUserRole} 
                        currentUserName={currentUser} 
                        tasks={tasks.filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} 
                        onToggleTask={onToggleTask} 
                        onEditTask={onEditTask} 
                        onDeleteTask={onDeleteTask} 
                        onToggleMissing={onToggleMissing} 
                        onSetInProgress={onSetInProgress} 
                        onToggleBlock={handleSearchIconClick} 
                        onToggleManualBlock={onToggleManualBlock} 
                        onExhaustSearch={onExhaustSearch} 
                        onMarkAsIncorrect={onMarkAsIncorrect} 
                        onAddNote={onAddNote} 
                        onReleaseTask={onReleaseTask} 
                        onAuditPart={handleAuditClick} 
                        resolveName={resolveName} 
                        missingReasons={missingReasons} 
                        hasPermission={hasPermission} 
                    />
                    </div>
                )}
                {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && <AnalyticsTab tasks={tasks} onFetchArchivedTasks={props.onFetchArchivedTasks} systemBreaks={props.systemBreaks} resolveName={resolveName} mapSectors={props.mapSectors} workplaces={props.workplaces} />}
                {activeTab === 'settings' && hasPermission('perm_tab_settings') && <SettingsTab hasPermission={hasPermission} currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateNickname={props.onUpdateNickname} onUpdateExportPermission={props.onUpdateExportPermission} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onUpdateWorkplace={props.onUpdateWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onUpdateLogisticsOperation={props.onUpdateLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} mapSectors={props.mapSectors} onAddMapSector={props.onAddMapSector} onDeleteMapSector={props.onDeleteMapSector} onUpdateMapSector={props.onUpdateMapSector} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={id => props.onRejectPartRequest(id)} onArchiveTasks={onArchiveTasks} onDailyClosing={props.onDailyClosing} onWeeklyClosing={props.onWeeklyClosing} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomMap={bomMap} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={id => props.onRejectBOMRequest(id)} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={installPrompt} onInstallApp={onInstallApp} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} resolveName={resolveName} onGetDocCount={onGetDocCount} onPurgeOldTasks={onPurgeOldTasks} onExportTasksJSON={onExportTasksJSON} onUpdateAdminKey={props.onUpdateAdminKey} onToggleAdminLock={props.onToggleAdminLock} />}
                {activeTab === 'bom' && hasPermission('perm_tab_bom') && <BOMScreen parts={parts} workplaces={workplaces} bomMap={bomMap} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
                {activeTab === 'missing' && hasPermission('perm_tab_missing') && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} resolveName={resolveName} />}
                {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={partNumbersList} onRequestPart={props.onRequestPart} resolveName={resolveName} />}
                {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} resolveName={resolveName} />}
                {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={id => props.onDeleteRole(id)} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
                </div>
            </div>
          </>
      )}

      {auditStartTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditStartTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white mb-6 text-center uppercase tracking-widest">{t('audit_start_title')}</h3>
                  <p className="text-gray-300 text-center mb-10 text-base leading-relaxed">{t('audit_start_desc', { part: (auditStartTask?.partNumber || '') as string })}</p>
                  <div className="flex gap-4">
                      <button onClick={() => setAuditStartTask(null)} className="flex-1 py-5 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs tracking-widest">{t('btn_cancel')}</button>
                      <button onClick={handleConfirmStartAudit} className="flex-1 py-5 bg-[#926a05] hover:bg-[#a67c06] text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest border-2 border-[#b68406]">Potvrdiť začiatok</button>
                  </div>
              </div>
          </div>,
          document.body
      )}

      {auditFinishTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditFinishTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-lg p-8 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white mb-8 text-center uppercase tracking-widest">{t('audit_finish_title')}</h3>
                  <div className="mb-8">
                      <label className="block text-gray-400 text-xs font-black uppercase mb-3 tracking-[0.2em]">{t('audit_finish_note')}</label>
                      <textarea value={auditNote} onChange={(e) => setAuditNote(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded-xl text-white px-5 py-4 focus:outline-none focus:ring-2 focus:ring-[#926a05] h-40 text-base font-medium placeholder-gray-500" placeholder="..." autoFocus />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                      <button onClick={() => handleConfirmFinishAudit('found', auditNote)} disabled={!auditNote.trim()} className={`py-5 rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest flex items-center justify-center gap-2 border-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 border-gray-700 cursor-not-allowed' : 'bg-green-600 border-green-500 text-white'}`}>✅ {t('audit_found_btn')}</button>
                      <button onClick={() => handleConfirmFinishAudit('missing', auditNote)} disabled={!auditNote.trim()} className={`py-5 rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest flex items-center justify-center gap-2 border-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 border-gray-700 cursor-not-allowed' : 'bg-red-600 border-red-500 text-white'}`}>❌ {t('audit_missing_btn')}</button>
                  </div>
                  <button onClick={() => setAuditFinishTask(null)} className="w-full py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-[10px] tracking-widest">{t('btn_cancel')}</button>
              </div>
          </div>,
          document.body
      )}

      {searchConfirmTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setSearchConfirmTask(null)}>
              <div className="bg-gray-800 border-2 border-gray-600 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                  <div className="text-center mb-8">
                      <h3 className="text-2xl font-black text-white mb-3 uppercase tracking-tighter">
                          {language === 'sk' ? 'Našiel si tovar?' : 'Found the item?'}
                      </h3>
                      <p className="text-gray-400 text-base leading-relaxed">
                          {language === 'sk' 
                            ? `Potvrď, či sa diel ${searchConfirmTask.partNumber} podarilo nájsť.` 
                            : `Confirm if you found part ${searchConfirmTask.partNumber}.`}
                      </p>
                  </div>
                  <div className="flex gap-4 mb-4">
                      <button 
                        onClick={() => handleConfirmFoundItem(true)} 
                        className="flex-1 py-5 bg-green-600 hover:bg-green-500 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 border-green-500"
                      >
                          ✅ {language === 'sk' ? 'Áno, našiel' : 'Yes, found'}
                      </button>
                      <button 
                        onClick={() => handleConfirmFoundItem(false)} 
                        className="flex-1 py-5 bg-red-600 hover:bg-red-500 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 border-red-500"
                      >
                          ❌ {language === 'sk' ? 'Nie, nenašiel' : 'No, not found'}
                      </button>
                  </div>
                  <button onClick={() => setSearchConfirmTask(null)} className="w-full py-3 bg-gray-700 text-gray-400 rounded-xl hover:bg-gray-600 font-bold transition-all uppercase text-[10px] tracking-widest">
                      {t('btn_cancel')}
                  </button>
              </div>
          </div>,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React, { useMemo, useState, useEffect } from 'react';
import { db } from '../../../firebase';
import { collection, getDocs, query, where, limit } from 'firebase/firestore';
import { Task, SystemBreak, MapSector, DBItem } from '../../../App';
import { useLanguage } from '../../LanguageContext';
import AnalyticsExportPanel from './AnalyticsExportPanel';
import HighRunnerSection from './HighRunnerSection';
import HourlyChartSection from './HourlyChartSection';
import QualityAuditSection from './QualityAuditSection';
import WorkerDetailModal from './WorkerDetailModal';

declare var XLSX: any;

interface AnalyticsTabProps {
  tasks: Task[];
  onFetchArchivedTasks: () => Promise<Task[]>;
  systemBreaks: SystemBreak[];
  resolveName: (username?: string | null) => string;
  mapSectors: MapSector[];
  workplaces: DBItem[];
}

type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH';
type ShiftFilter = 'ALL' | 'MORNING' | 'AFTERNOON';

