              <div className="bg-blue-500/10 p-2 rounded-lg text-blue-400">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 m-4 0a2 2 0 114 0" /></svg>
              </div>
            </div>
            <h4 className="text-3xl font-black text-white font-mono tracking-tighter mb-6">{s.rides} <span className="text-xs font-normal text-slate-500 uppercase">Jázd</span></h4>
            <div className="pt-4 border-t border-white/5 flex justify-between items-center">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Ø Vzdialenosť</p>
              <p className="text-sm font-black text-teal-400 font-mono">{s.avgDist} <span className="text-[10px] font-normal text-slate-600">bodov</span></p>
            </div>
          </div>
        )) : (
          <div className="col-span-4 py-12 text-center border-2 border-dashed border-slate-800 rounded-2xl text-slate-600 font-black uppercase text-xs">Žiadne logistické dáta</div>
        )}
      </div>
    </div>
  );
};

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ tasks: liveTasks, onFetchArchivedTasks, systemBreaks, resolveName, mapSectors, workplaces, systemConfig }) => {
  const [filterMode, setFilterMode] = useState<FilterMode>('TODAY');
  const [shiftFilter, setShiftFilter] = useState<ShiftFilter>('ALL');
  const [archivedTasks, setArchivedTasks] = useState<Task[]>([]);
  const [isLoadingArchive, setIsLoadingArchive] = useState(false);
  const [lastFetchTime, setLastFetchTime] = useState<number>(0);
  const [canExport, setCanExport] = useState(false);
  const [selectedWorkerData, setSelectedWorkerData] = useState<{ name: string; tasks: Task[] } | null>(null);
  const { t, language } = useLanguage();

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return '< 1 min';
    if (minutes >= 60) return `${Math.floor(minutes / 60)}h ${minutes % 60}m`;
    return `${minutes} min`;
  };

  useEffect(() => {
    const checkExportPermission = async () => {
      const storedUser = localStorage.getItem('app_user');
      if (!storedUser) return;
      try {
        const q = query(collection(db, 'users'), where('username', '==', storedUser));
        const querySnapshot = await getDocs(q);
        if (!querySnapshot.empty) {
          const userData = querySnapshot.docs[0].data();
          setCanExport(userData.canExportAnalytics === true);
        }
      } catch (error) { console.error("Error checking analytics permission:", error); }
    };
    checkExportPermission();
  }, []);

  const tasks = useMemo(() => [...liveTasks, ...archivedTasks], [liveTasks, archivedTasks]);

  useEffect(() => {
    const FIVE_MINUTES = 5 * 60 * 1000;
    if (archivedTasks.length === 0 || (Date.now() - lastFetchTime > FIVE_MINUTES)) {
      const load = async () => {
        setIsLoadingArchive(true);
        try {
          const results: Task[] = [];
          const now = new Date();
          const currentYear = now.getFullYear();
          const draftsSnap = await getDocs(query(collection(db, 'archive_drafts'), limit(500)));
          draftsSnap.forEach(d => results.push({ ...(d.data() as Task), id: d.id }));

          const getISOWeek = (date: Date) => {
            const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
            const dayNum = d.getUTCDay() || 7;
            d.setUTCDate(d.getUTCDate() + 4 - dayNum);
            const yearStart = new Date(Date.UTC(date.getFullYear(), 0, 1));
            return Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
          };

          const currentWeek = getISOWeek(now);
          const monthAgo = new Date(now.getTime() - 31 * 24 * 60 * 60 * 1000);
          const startWeek = getISOWeek(monthAgo);
          const weekCollections = [];
          for (let w = startWeek; w <= currentWeek; w++) { weekCollections.push(`sanon_${currentYear}_${w}`); }

          for (const colName of [...new Set(weekCollections)]) {
            try {
              const s = await getDocs(collection(db, colName));
              s.forEach(d => results.push({ ...(d.data() as Task), id: d.id }));
            } catch (e) { }
          }
          setArchivedTasks(results);
          setLastFetchTime(Date.now());
        } catch (err) { console.error("Archive auto-sync error:", err); }
        finally { setIsLoadingArchive(false); }
      };
      load();
    }
  }, [lastFetchTime, archivedTasks.length]);

  const filteredTasks = useMemo(() => {
    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    return tasks.filter(task => {
      const referenceTime = task.completedAt || task.createdAt;
      if (!referenceTime) return false;

      const taskDate = new Date(referenceTime);
      const taskDayStart = new Date(taskDate.getFullYear(), taskDate.getMonth(), taskDate.getDate());

      let passesTimeFilter = false;
      switch (filterMode) {
        case 'TODAY': passesTimeFilter = taskDayStart.getTime() === todayStart.getTime(); break;
        case 'YESTERDAY':
          const yesterdayStart = new Date(todayStart);
          yesterdayStart.setDate(yesterdayStart.getDate() - 1);
          passesTimeFilter = taskDayStart.getTime() === yesterdayStart.getTime();
          break;
        case 'WEEK': passesTimeFilter = referenceTime >= (todayStart.getTime() - (7 * 86400000)); break;
        case 'MONTH': passesTimeFilter = taskDate.getMonth() === now.getMonth() && taskDate.getFullYear() === now.getFullYear(); break;
        default: passesTimeFilter = true;
      }

      if (!passesTimeFilter) return false;
      if (shiftFilter === 'ALL') return true;

      const hours = taskDate.getHours();
      if (shiftFilter === 'MORNING') return hours >= 4 && hours < 14;
      if (shiftFilter === 'AFTERNOON') return hours >= 14 && hours < 24;
      return true;
    });
  }, [tasks, filterMode, shiftFilter]);

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    if (history && history.length > 0) {
      history.forEach(session => {
        const overlapStart = Math.max(startTime, session.start);
        const overlapEnd = Math.min(endTime, session.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    if (systemBreaks && systemBreaks.length > 0) {
      systemBreaks.forEach(br => {
        const overlapStart = Math.max(startTime, br.start);
        const overlapEnd = Math.min(endTime, br.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    return totalBlocked;
  };

  const stats = useMemo(() => {
    const highRunnersMap: Record<string, { load: number, pal: number, taskRequests: number, totalTasks: number }> = {};
    const workplacesMap: Record<string, { load: number, pal: number, taskRequests: number, totalTasks: number }> = {};
    const hourlyStatsMap: Record<number, { production: number, logistics: number }> = {};
    const missingPartsMap: Record<string, number> = {};
    const sectorRidesMap: Record<string, { count: number, totalDist: number }> = {};

    for (let i = 0; i < 24; i++) hourlyStatsMap[i] = { production: 0, logistics: 0 };

    let realErrorsCount = 0, totalAuditedMissing = 0, falseAlarmsCount = 0, grandTotalExecutionTime = 0;
    const workerStatsMap: Record<string, any> = {};

    const performanceTasks = filteredTasks.filter(t => t.status !== 'incorrectly_entered' && t.auditResult !== 'NOK');

    let globalFullDist = 0;
    let globalEmptyDist = 0;
    let globalRides = 0;
    const lastWpPerWorker: Record<string, {x: number, y: number}> = {};
    const lastValidTaskPerWorker: Record<string, { time: number, source: string, target: string }> = {};
    const defaultOrigin = { x: systemConfig.mapOriginX || 0, y: systemConfig.mapOriginY || 0 };

    const chronTasks = [...performanceTasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));

    chronTasks.forEach(task => {
      const qtyVal = parseFloat((task.quantity || '0').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      const refTime = (task.completedAt || task.createdAt || 0);
      const hour = refTime ? new Date(refTime).getHours() : -1;

      const isProductionFallback = (task.isProduction === true) || (!task.isLogistics && !!task.workplace);
      const isLogisticsFallback = (task.isLogistics === true) || (!task.isProduction && !task.workplace && !!task.partNumber);

      if (task.isMissing === true) {
        if (task.partNumber) missingPartsMap[task.partNumber] = (missingPartsMap[task.partNumber] || 0) + 1;
        if (task.auditResult) {
          totalAuditedMissing++;
          if (task.auditResult === 'NOK') realErrorsCount++;
          else if (task.auditResult === 'OK') falseAlarmsCount++;
        }
      }

      if (task.pickedFromSectorId && task.workplace && task.isDone && task.completedBy) {
        const worker = task.completedBy;
        if (!workerStatsMap[worker]) {
            workerStatsMap[worker] = { 
                username: worker, name: resolveName(worker), count: 0, totalVolume: 0, totalExecutionMs: 0,
                totalStandardMin: 0, totalReactionMs: 0, reactionCount: 0, missingReported: 0, realErrors: 0,
                uniqueDays: new Set<string>(), totalFullDist: 0, totalEmptyDist: 0, totalRides: 0, multiLoadBonus: 0
            };
        }
        const ws = workerStatsMap[worker];
        const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
        const wp = workplaces.find(w => w.value === task.workplace);

        if (sector && wp) {
            const tripCount = task.quantityUnit === 'pallet' ? Math.max(1, Math.floor(qtyVal)) : 1;

            // ANTI-CHEAT: Zistenie hromadného potvrdenia (rovnaká trasa, čas < 45s)
            const lastTask = lastValidTaskPerWorker[worker];
            const isCheatWindow = lastTask && (refTime - lastTask.time < 45000) && 
                                 (lastTask.source === task.pickedFromSectorId) && 
                                 (lastTask.target === task.workplace);

            if (isCheatWindow) {
               ws.multiLoadBonus += 0.2; // Odmena za efektivitu (multi-load)
            } else {
                for (let i = 0; i < tripCount; i++) {
                    globalRides++;
                    ws.totalRides++;

                    if (!sectorRidesMap[task.pickedFromSectorId]) sectorRidesMap[task.pickedFromSectorId] = { count: 0, totalDist: 0 };
                    sectorRidesMap[task.pickedFromSectorId].count++;

                    const startPoint = (i === 0) ? (lastWpPerWorker[worker] || defaultOrigin) : { x: wp.coordX || 0, y: wp.coordY || 0 };
                    const edx = (sector.coordX || 0) - startPoint.x;
                    const edy = (sector.coordY || 0) - startPoint.y;
                    const ed = Math.sqrt(edx*edx + edy*edy) / 10;
                    globalEmptyDist += ed;
                    ws.totalEmptyDist += ed;

                    const dx = (wp.coordX || 0) - (sector.coordX || 0);
                    const dy = (wp.coordY || 0) - (sector.coordY || 0);
                    const d = Math.sqrt(dx*dx + dy*dy) / 10;
                    globalFullDist += d;
                    ws.totalFullDist += d;
                    sectorRidesMap[task.pickedFromSectorId].totalDist += d;
                }
                lastWpPerWorker[worker] = { x: wp.coordX || 0, y: wp.coordY || 0 };
            }
            lastValidTaskPerWorker[worker] = { time: refTime, source: task.pickedFromSectorId, target: task.workplace };
        }
      }

      if (isProductionFallback && task.partNumber && task.partNumber !== '-') {
        const pn = task.partNumber;
        if (!highRunnersMap[pn]) highRunnersMap[pn] = { load: 0, pal: 0, taskRequests: 0, totalTasks: 0 };
        highRunnersMap[pn].totalTasks++;
        highRunnersMap[pn].load += loadPoints;
        if (task.quantityUnit === 'pallet') highRunnersMap[pn].pal += qtyVal;
        else highRunnersMap[pn].taskRequests += 1;
      }

      if (isProductionFallback && task.workplace) {
        const wp = task.workplace;
        if (!workplacesMap[wp]) workplacesMap[wp] = { load: 0, pal: 0, taskRequests: 0, totalTasks: 0 };
        workplacesMap[wp].totalTasks++;
        workplacesMap[wp].load += loadPoints;
        if (task.quantityUnit === 'pallet') workplacesMap[wp].pal += qtyVal;
        else workplacesMap[wp].taskRequests += 1;
      }

      if (hour >= 0 && hour < 24) {
        if (isProductionFallback) hourlyStatsMap[hour].production += loadPoints;
        else if (isLogisticsFallback) hourlyStatsMap[hour].logistics += loadPoints;
      }

      if (task.isDone && task.completedBy) {
        const worker = task.completedBy;
        if (!workerStatsMap[worker]) {
          workerStatsMap[worker] = { 
            username: worker, name: resolveName(worker), count: 0, totalVolume: 0, totalExecutionMs: 0,
            totalStandardMin: 0, totalReactionMs: 0, reactionCount: 0, missingReported: 0, realErrors: 0,
            uniqueDays: new Set<string>(), totalFullDist: 0, totalEmptyDist: 0, totalRides: 0, multiLoadBonus: 0
          };
        }
        const ws = workerStatsMap[worker];
        ws.count += 1;
        ws.totalVolume += loadPoints;
        ws.uniqueDays.add(new Date(task.completedAt!).toLocaleDateString('sk-SK'));

        if (task.startedAt && task.completedAt) {
          let execution = task.completedAt - task.startedAt;
          execution -= calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
          if (execution > 0) { ws.totalExecutionMs += execution; grandTotalExecutionTime += execution; }
          ws.totalStandardMin += (task.standardTime || 0);
        }
        if (task.createdAt && task.startedAt) {
          const react = task.startedAt - task.createdAt;
          if (react > 0) { ws.totalReactionMs += react; ws.reactionCount++; }
        }
        if (task.isMissing) {
          ws.missingReported++;
          if (task.auditResult === 'NOK') ws.realErrors++;
        }
      }
    });

    const sectorStats = mapSectors.map(s => {
        const rideData = sectorRidesMap[s.id] || { count: 0, totalDist: 0 };
        return {
            id: s.id,
            name: s.name,
            color: s.color || 'slate',
            rides: rideData.count,
            avgDist: rideData.count > 0 ? (rideData.totalDist / rideData.count).toFixed(1) : '0'
        };
    }).sort((a,b) => b.rides - a.rides);

    const workerStats = Object.values(workerStatsMap).map((ws: any) => {
      const numDays = Math.max(ws.uniqueDays.size, 1);
      const totalAvailableMin = numDays * 450;
      const pureWorkMin = ws.totalExecutionMs / 60000;
      const utilPercent = ( (pureWorkMin * 1.15) / totalAvailableMin ) * 100;
      const perfRatio = (ws.totalStandardMin > 0 && pureWorkMin > 0) ? (ws.totalStandardMin / pureWorkMin) * 100 : 0;
      const avgReactSec = ws.reactionCount > 0 ? (ws.totalReactionMs / ws.reactionCount) / 1000 : 0;
      const confidence = ws.missingReported > 0 ? ((ws.missingReported - ws.realErrors) / ws.missingReported) * 100 : 100;
      const logEfficiency = ws.totalFullDist > 0 ? (ws.totalFullDist / (ws.totalFullDist + ws.totalEmptyDist)) * 100 : 100;

      const sQuality = (confidence / 100) * 3.0;
      const sUtil = (Math.min(utilPercent, 100) / 100) * 2.5;
      const sNorms = perfRatio > 0 ? (Math.min(perfRatio, 120) / 120) * 2.0 : 1.5;
      let sReact = 0;
      if (avgReactSec > 0) {
        if (avgReactSec < 60) sReact = 1.0;
        else if (avgReactSec < 180) sReact = 0.5;
      } else sReact = 0.5;

      // LOGISTIKA: Efektivita trás + bonus za Multi-Load (hromadné potvrdenia)
      const sLogistics = ((logEfficiency / 100) * 1.0) + Math.min(ws.multiLoadBonus, 0.5);

      const index = parseFloat((sQuality + sUtil + sNorms + sReact + sLogistics).toFixed(1));
      return { ...ws, index, pureWorkMin, utilPercent, perfRatio, avgReactSec, logEfficiency };
    }).sort((a, b) => b.index - a.index);

    const logEfficiency = globalFullDist > 0 ? (globalFullDist / (globalFullDist + globalEmptyDist)) * 100 : 100;

    return { 
      total: performanceTasks.length, done: performanceTasks.filter(t => t.isDone).length, 
      efficiency: performanceTasks.length <= 0 ? 0 : Math.round((performanceTasks.filter(t => t.isDone).length / performanceTasks.length) * 100),
      totalVolume: Object.values(workerStatsMap).reduce((s, w) => s + w.totalVolume, 0),
      avgLead: 0, avgReaction: 0, grandTotalExecutionTime, 
      workerStats, 
      topHighRunners: Object.entries(highRunnersMap).sort(([, a], [, b]) => b.load - a.load).slice(0, 3).map(([pn, d]) => ({ partNumber: pn, ...d })),
      topWorkplaces: Object.entries(workplacesMap).sort(([, a], [, b]) => b.load - a.load).slice(0, 3).map(([wp, d]) => ({ workplace: wp, ...d })),
      hourlyData: Object.entries(hourlyStatsMap).map(([h, v]) => ({ hour: parseInt(h), label: `${h.padStart(2, '0')}:00`, production: v.production, logistics: v.logistics }))
        .filter(d => shiftFilter === 'MORNING' ? (d.hour >= 4 && d.hour < 14) : shiftFilter === 'AFTERNOON' ? (d.hour >= 14 && d.hour < 24) : true),
      quality: { realErrorsCount, falseAlarmsCount, totalAuditedMissing, topMissingParts: Object.entries(missingPartsMap).sort(([, a], [, b]) => b - a).slice(0, 3).map(([pn, count]) => ({ partNumber: pn, count })) },
      sectorStats,
      driving: { totalFullDist: globalFullDist, totalEmptyDist: globalEmptyDist, totalRides: globalRides, logEfficiency }
    };
  }, [filteredTasks, systemBreaks, resolveName, shiftFilter, mapSectors, workplaces, systemConfig]);

  const handleExportSummaryTable = () => {
    if (typeof XLSX === 'undefined') return;
    const excelData = stats.workerStats.map((ws, idx) => ({
      'Poradie': idx + 1,
      'Meno': ws.name,
      'INDEX SCORE': ws.index.toFixed(1),
      'Vybavené úlohy': ws.count,
      'Objem (pal/ks)': ws.totalVolume.toFixed(1),
      'Čistý čas práce': formatDuration(ws.totalExecutionMs),
      'Využitie zmeny': `${ws.utilPercent.toFixed(1)}%`,
      'Plnenie normy': `${ws.perfRatio.toFixed(0)}%`,
      'Logistická efekt.': `${ws.logEfficiency.toFixed(0)}%`,
      'Priem. Reakcia': `${Math.round(ws.avgReactSec)}s`
    }));
    const ws = XLSX.utils.json_to_sheet(excelData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Výkonnosť_Skladníkov");
    XLSX.writeFile(wb, `Vykonnost_Skladnikov_${filterMode}_${new Date().getTime()}.xlsx`);
  };

  const getPeriodLabel = () => {
    switch (filterMode) {
      case 'TODAY': return language === 'sk' ? 'DNEŠNÝ PREHĽAD' : 'TODAY VIEW';
      case 'YESTERDAY': return language === 'sk' ? 'VČERAJŠÍ PREHĽAD' : 'YESTERDAY VIEW';
      case 'WEEK': return language === 'sk' ? 'TÝŽDENNÝ PREHĽAD' : 'WEEKLY VIEW';
      case 'MONTH': return language === 'sk' ? 'MESAČNÝ PREHĽAD' : 'MONTHLY VIEW';
      default: return '';
    }
  };

  const getIndexColor = (val: number) => {
    if (val >= 8) return 'text-emerald-500';
    if (val >= 5) return 'text-amber-500';
    return 'text-red-500';
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h1 className="text-2xl sm:text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('analytics_title')}</h1>
        {isLoadingArchive && (
          <div className="flex items-center gap-3 bg-slate-900 px-4 py-2 rounded-xl border border-slate-800">
            <div className="w-3 h-3 border-2 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
            <span className="text-[10px] font-black text-teal-400 uppercase tracking-widest">{t('loading_hist')}</span>
          </div>
        )}
      </div>

      <AnalyticsExportPanel canExport={canExport} tasks={tasks} systemBreaks={systemBreaks} resolveName={resolveName} t={t} language={language} />

      <div className="bg-gray-800/40 p-4 rounded-2xl shadow-md border border-gray-700 flex flex-col gap-6">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-6">
          <div className="flex flex-wrap gap-2 justify-center">
            {(['TODAY', 'YESTERDAY', 'WEEK', 'MONTH'] as FilterMode[]).map(mode => (
              <button key={mode} onClick={() => setFilterMode(mode)} className={`px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${filterMode === mode ? 'bg-teal-600 text-white shadow-lg' : 'bg-slate-800/50 text-gray-400 hover:text-white'}`}>{t(`filter_${mode.toLowerCase()}` as any)}</button>
            ))}
          </div>
          <div className="bg-slate-950/80 p-1.5 rounded-2xl flex border border-slate-700 shadow-inner h-14 min-w-[300px]">
            <button onClick={() => setShiftFilter('ALL')} className={`flex-1 rounded-xl text-xs font-black uppercase tracking-widest duration-200 ${shiftFilter === 'ALL' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>{language === 'sk' ? 'Všetky' : 'All'}</button>
            <button onClick={() => setShiftFilter('MORNING')} className={`flex-1 rounded-xl text-xs font-black uppercase tracking-widest duration-200 ${shiftFilter === 'MORNING' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>{language === 'sk' ? 'Ranná' : 'Morning'}</button>
            <button onClick={() => setShiftFilter('AFTERNOON')} className={`flex-1 rounded-xl text-xs font-black uppercase tracking-widest duration-200 ${shiftFilter === 'AFTERNOON' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>{language === 'sk' ? 'Poobedná' : 'Afternoon'}</button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-5">
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-blue-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_total')}</p>
          <p className="text-3xl font-black text-white mt-2 font-mono leading-none">{stats.total}</p>
          <p className="text-xs font-bold text-blue-400/80 mt-1 uppercase tracking-widest">{stats.totalVolume.toFixed(1)} {language === 'sk' ? 'pal/ks' : 'pal/pcs'}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-emerald-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_worked')}</p>
          <p className="text-3xl font-black text-emerald-400 mt-2 font-mono">{formatDuration(stats.grandTotalExecutionTime)}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-purple-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_lead')}</p>
          <p className="text-3xl font-black text-purple-400 mt-2 font-mono">{formatDuration(stats.avgLead)}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-amber-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_react')}</p>
          <p className="text-3xl font-black text-amber-400 mt-2 font-mono">{formatDuration(stats.avgReaction)}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-teal-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{language === 'sk' ? 'EFEKTIVITA' : 'EFFICIENCY'}</p>
          <p className="text-3xl font-black text-teal-400 mt-2 font-mono">{stats.efficiency} %</p>
        </div>
      </div>

      <div className="bg-slate-950/40 border border-slate-800 p-6 rounded-3xl shadow-2xl overflow-hidden">
        <div className="flex items-center justify-between mb-8 border-b border-white/5 pb-6">
          <h3 className="text-sm font-black text-white uppercase tracking-[0.25em]">{t('table_title')}</h3>
          <button 
            onClick={handleExportSummaryTable}
            className="bg-green-700 hover:bg-green-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg active:scale-95 flex items-center gap-2 border border-green-500"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            EXPORT DO EXCELU
          </button>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-separate border-spacing-y-3 min-w-[700px]">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                <th className="pb-4 px-6">{t('th_rank')}</th>
                <th className="pb-4 px-2">{t('th_name')}</th>
                <th className="pb-4 px-2 text-center text-teal-400">INDEX</th>
                <th className="pb-4 px-2 text-right">{t('th_done')}</th>
                <th className="pb-4 px-2 text-right text-sky-400">📦 {language === 'sk' ? 'OBJEM' : 'VOLUME'}</th>
                <th className="pb-4 px-6 text-right text-emerald-400">{t('th_work_time')}</th>
              </tr>
            </thead>
            <tbody>
              {stats.workerStats.map((ws: any, idx: number) => (
                <tr key={ws.username} className={`group transition-all hover:bg-slate-800/60 ${idx === 0 ? 'bg-slate-800/40 shadow-[0_0_20px_rgba(20,184,166,0.1)]' : 'bg-slate-900/40'}`}>
                  <td className={`py-5 px-6 first:rounded-l-2xl text-slate-500 font-mono text-base ${idx === 0 ? 'border-y border-l border-teal-500/30' : ''}`}>{idx + 1}</td>
                  <td 
                    onClick={() => setSelectedWorkerData({ 
                      name: ws.name, 
                      tasks: filteredTasks.filter(t => t.completedBy === ws.username) 
                    })}
                    className={`py-5 px-2 font-black text-lg uppercase tracking-tight cursor-pointer hover:text-teal-400 transition-colors ${idx === 0 ? 'text-teal-400 border-y border-teal-500/30' : 'text-slate-200'}`}
                  >
                    <div className="flex items-center gap-3">{idx === 0 && <span className="text-amber-400 animate-pulse text-xl">★</span>}{ws.name}</div>
                  </td>
                  <td className={`py-5 px-2 text-center font-black font-mono text-xl ${getIndexColor(ws.index)} ${idx === 0 ? 'border-y border-teal-500/30' : ''}`}>
                    {ws.index.toFixed(1)}
                  </td>
                  <td className={`py-5 px-2 text-right text-teal-500 font-black font-mono text-lg ${idx === 0 ? 'border-y border-teal-500/30' : ''}`}>{ws.count}</td>
                  <td className={`py-5 px-2 text-right text-sky-400 font-black font-mono text-lg ${idx === 0 ? 'border-y border-teal-500/30' : ''}`}>{Number(ws.totalVolume.toFixed(1))}</td>
                  <td className={`py-5 px-6 last:rounded-r-2xl text-right text-emerald-400 font-black font-mono text-base ${idx === 0 ? 'border-y border-r border-teal-500/30' : ''}`}>{formatDuration(ws.totalExecutionMs)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <QualityAuditSection data={stats.quality} t={t} />
      <HighRunnerSection topHighRunners={stats.topHighRunners} topWorkplaces={stats.topWorkplaces} t={t} />
      <HourlyChartSection hourlyData={stats.hourlyData} t={t} />

      <DrivingMetrics 
        totalKm={stats.driving.totalFullDist} 
        emptyKm={stats.driving.totalEmptyDist} 
        rides={stats.driving.totalRides} 
        efficiency={stats.driving.logEfficiency} 
      />

      <LogisticsSectorsSection data={stats.sectorStats} t={t} />

      {selectedWorkerData && (
        <WorkerDetailModal 
          name={selectedWorkerData.name}
          tasks={selectedWorkerData.tasks}
          periodLabel={getPeriodLabel()}
          systemBreaks={systemBreaks}
          onClose={() => setSelectedWorkerData(null)}
          mapSectors={mapSectors}
          workplaces={workplaces}
          systemConfig={systemConfig}
        />
      )}
    </div>
  );
};

export default AnalyticsTab;

import React, { useMemo } from 'react';
import { createPortal } from 'react-dom';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig } from '../../../App';
import { useLanguage } from '../../LanguageContext';

interface WorkerDetailModalProps {
  name: string;
  tasks: Task[];
  periodLabel: string;
  systemBreaks: SystemBreak[];
  onClose: () => void;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
}

const WorkerDetailModal: React.FC<WorkerDetailModalProps> = ({ name, tasks, periodLabel, systemBreaks, onClose, mapSectors, workplaces, systemConfig }) => {
  const { t, language } = useLanguage();

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    if (history && history.length > 0) {
      history.forEach(session => {
        const overlapStart = Math.max(startTime, session.start);
        const overlapEnd = Math.min(endTime, session.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    systemBreaks.forEach(br => {
      const overlapStart = Math.max(startTime, br.start);
      const overlapEnd = Math.min(endTime, br.end || endTime);
      if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
    });
    return totalBlocked;
  };

  const stats = useMemo(() => {
    let totalLoad = 0;
    let palCount = 0;
    let pcsTasks = 0;
    let missingReported = 0;
    let realErrors = 0;
    let totalExecMs = 0;
    let totalStandardMin = 0;
    let totalReactionMs = 0;
    let reactionCount = 0;
    let durations: number[] = [];

    let totalFullDist = 0;
    let totalEmptyDist = 0;
    let multiLoadBonus = 0;
    const defaultOrigin = { x: systemConfig.mapOriginX || 0, y: systemConfig.mapOriginY || 0 };
    let lastWpCoords: { x: number, y: number } | null = null;
    let lastTaskInfo: { time: number, source: string, target: string } | null = null;

    const workplacesMap: Record<string, number> = {};
    const partsMap: Record<string, number> = {};
    const missingHistory: Task[] = [];
    const uniqueDaysWorked = new Set<string>();

    const sortedTasks = [...tasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));

    sortedTasks.forEach(task => {
      const refTime = (task.completedAt || task.createdAt || 0);
      if (task.completedAt) {
        const dateKey = new Date(task.completedAt).toLocaleDateString('sk-SK');
        uniqueDaysWorked.add(dateKey);
      }

      const qtyVal = parseFloat((task.quantity || '0').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      totalLoad += loadPoints;

      if (task.quantityUnit === 'pallet') palCount += qtyVal;
      else pcsTasks++;

      if (task.pickedFromSectorId && task.workplace) {
          const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
          const wp = workplaces.find(w => w.value === task.workplace);
          if (sector && wp) {
              // ANTI-CHEAT VALIDATION (45s window)
              const isCheatWindow = lastTaskInfo && (refTime - lastTaskInfo.time < 45000) && 
                                   (lastTaskInfo.source === task.pickedFromSectorId) && 
                                   (lastTaskInfo.target === task.workplace);

              if (isCheatWindow) {
                multiLoadBonus += 0.2;
              } else {
                  const tripCount = task.quantityUnit === 'pallet' ? Math.max(1, Math.floor(qtyVal)) : 1;
                  for (let i = 0; i < tripCount; i++) {
                      const startPoint = (i === 0) ? (lastWpCoords || defaultOrigin) : { x: wp.coordX || 0, y: wp.coordY || 0 };
                      const edx = (sector.coordX || 0) - startPoint.x;
                      const edy = (sector.coordY || 0) - startPoint.y;
                      totalEmptyDist += Math.sqrt(edx*edx + edy*edy) / 10;

                      const dx = (wp.coordX || 0) - (sector.coordX || 0);
                      const dy = (wp.coordY || 0) - (sector.coordY || 0);
                      totalFullDist += Math.sqrt(dx*dx + dy*dy) / 10;
                  }
                  lastWpCoords = { x: wp.coordX || 0, y: wp.coordY || 0 };
              }
              lastTaskInfo = { time: refTime, source: task.pickedFromSectorId, target: task.workplace };
          }
      }

      if (task.isMissing) {
        missingReported++;
        if (task.auditResult === 'NOK') realErrors++;
        if (missingHistory.length < 5) missingHistory.push(task);
      }

      if (task.startedAt && task.completedAt) {
        let exec = task.completedAt - task.startedAt;
        exec -= calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
        if (exec > 0) {
          totalExecMs += exec;
          durations.push(exec);
          totalStandardMin += (task.standardTime || 0);
        }
      }

      if (task.createdAt && task.startedAt) {
        const react = task.startedAt - task.createdAt;
        if (react > 0) {
          totalReactionMs += react;
          reactionCount++;
        }
      }

      const isProd = (task.isProduction === true) || (!task.isLogistics && !!task.workplace);
      if (isProd && task.workplace) workplacesMap[task.workplace] = (workplacesMap[task.workplace] || 0) + 1;
      if (task.partNumber) partsMap[task.partNumber] = (partsMap[task.partNumber] || 0) + 1;
    });

    const numDays = Math.max(uniqueDaysWorked.size, 1);
    const shiftTotalMinutes = 450; 
    const totalAvailableMinutes = numDays * shiftTotalMinutes;
    const pureWorkMinutes = totalExecMs / 60000;
    const effectiveWorkMinutes = pureWorkMinutes * 1.15; 
    const utilizationPercent = totalAvailableMinutes > 0 ? (effectiveWorkMinutes / totalAvailableMinutes) * 100 : 0;
    const performanceRatio = (totalStandardMin > 0 && pureWorkMinutes > 0) ? (totalStandardMin / pureWorkMinutes) * 100 : 0;
    const avgReactionSeconds = reactionCount > 0 ? (totalReactionMs / reactionCount) / 1000 : 0;
    const confidenceRating = missingReported > 0 ? ((missingReported - realErrors) / missingReported) * 100 : 100;
    const logEfficiency = totalFullDist > 0 ? (totalFullDist / (totalFullDist + totalEmptyDist)) * 100 : 100;

    const scoreQuality = (confidenceRating / 100) * 3.0;
    const scoreUtilization = (Math.min(utilizationPercent, 100) / 100) * 2.5;
    const scoreStandards = performanceRatio > 0 ? (Math.min(performanceRatio, 120) / 120) * 2.0 : 1.5; 
    const scoreReaction = avgReactionSeconds > 0 ? (avgReactionSeconds < 60 ? 1.0 : avgReactionSeconds < 180 ? 0.5 : 0) : 0.5;

    // Logistika skóre = Efektivita trás + Bonus za hromadné potvrdenie
    const scoreLogistics = ((logEfficiency / 100) * 1.0) + Math.min(multiLoadBonus, 0.5);

    const workerIndex = parseFloat((scoreQuality + scoreUtilization + scoreStandards + scoreReaction + scoreLogistics).toFixed(1));

    const avgMsPerPoint = durations.length > 0 ? totalExecMs / totalLoad : 0;
    const topWorkplaces = Object.entries(workplacesMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count }));
    const topParts = Object.entries(partsMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count }));

    return {
      totalLoad, palCount, pcsTasks, 
      confidenceRating, realErrors, missingReported, missingHistory,
      totalExecMs, 
      fastest: durations.length > 0 ? Math.min(...durations) : 0,
      longest: durations.length > 0 ? Math.max(...durations) : 0,
      avgMsPerPoint,
      topWorkplaces, topParts,
      utilizationPercent,
      pureWorkMinutes,
      effectiveWorkMinutes,
      numDays,
      totalAvailableMinutes,
      workerIndex,
      performanceRatio,
      avgReactionSeconds,
      totalFullDist,
      totalEmptyDist,
      logEfficiency,
      multiLoadBonus
    };
  }, [tasks, systemBreaks, mapSectors, workplaces, systemConfig]);

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return '< 1 min';
    if (minutes >= 60) return `${Math.floor(minutes / 60)}h ${minutes % 60}m`;
    return `${minutes} min`;
  };

  const formatMinutes = (totalMin: number) => {
    const h = Math.floor(totalMin / 60);
    const m = Math.round(totalMin % 60);
    return h > 0 ? `${h}h ${m}m` : `${m} min`;
  };

  const cardStyle = "bg-slate-800/40 border-t-4 p-6 rounded-2xl shadow-xl backdrop-blur-md relative overflow-hidden";

  const getUtilColor = (val: number) => {
    if (val > 85) return 'border-t-emerald-500';
    if (val > 60) return 'border-t-teal-500';
    return 'border-t-amber-500';
  };

  const getUtilBarColor = (val: number) => {
    if (val > 85) return 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
    if (val > 60) return 'bg-teal-500';
    return 'bg-amber-500';
  };

  const getIndexBorderColor = (val: number) => {
    if (val >= 8) return 'border-emerald-500';
    if (val >= 5) return 'border-amber-500';
    return 'border-red-500';
  };

  const getIndexTextColor = (val: number) => {
    if (val >= 8) return 'text-emerald-400';
    if (val >= 5) return 'text-amber-400';
    return 'text-red-400';
  };

  return createPortal(
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/95 backdrop-blur-xl p-4 animate-fade-in" onClick={onClose}>
      <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] shadow-2xl w-full max-w-5xl max-h-[95vh] overflow-y-auto custom-scrollbar relative" onClick={e => e.stopPropagation()}>

        <div className="p-8 sm:p-10 border-b border-slate-800 flex flex-col md:flex-row justify-between items-start md:items-center gap-6 bg-slate-800/30">
          <div className="space-y-1">
            <div className="flex items-center gap-3">
               <span className="bg-teal-500/20 text-teal-400 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-teal-500/30">{periodLabel}</span>
               <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">{tasks.length} {t('records')}</span>
            </div>
            <h2 className="text-5xl font-black text-white uppercase tracking-tighter leading-none">{name}</h2>
          </div>

          <div className="flex gap-3">
             <button onClick={onClose} className="p-4 rounded-full bg-slate-800/50 hover:bg-slate-700 text-slate-400 transition-all border border-slate-700 shadow-lg">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
             </button>
          </div>
        </div>

        <div className="p-8 sm:p-10 grid grid-cols-1 md:grid-cols-2 gap-8">

          <div className={`col-span-1 md:col-span-2 bg-slate-950/40 border-l-[12px] p-8 rounded-3xl shadow-2xl flex flex-col sm:flex-row items-center justify-between gap-8 ${getIndexBorderColor(stats.workerIndex)}`}>
            <div className="text-center sm:text-left">
              <h3 className="text-sm font-black text-slate-500 uppercase tracking-[0.3em] mb-2">CELKOVÝ INDEX SCORE</h3>
              <p className="text-xs text-slate-600 font-bold uppercase leading-relaxed max-w-sm">Komplexné vyhodnotenie kvality, využitia zmeny, plnenia noriem, logistickej efektivity a rýchlosti reakcie.</p>
            </div>
            <div className="flex items-baseline gap-2">
              <span className={`text-8xl font-black font-mono leading-none tracking-tighter ${getIndexTextColor(stats.workerIndex)}`}>{stats.workerIndex.toFixed(1)}</span>
              <span className="text-2xl font-black text-slate-700 font-mono">/10</span>
            </div>
          </div>

          <div className={`${cardStyle} ${getUtilColor(stats.utilizationPercent)}`}>
            <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-4">
              <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">{t('shift_utilization')}</h3>
              <span className="bg-slate-900 px-3 py-1 rounded-full text-[9px] font-black text-slate-500 uppercase">
                {stats.numDays} {stats.numDays === 1 ? 'DEŇ' : 'DNI'} @ 7.5h
              </span>
            </div>
            <div className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Čistý čas práce</p>
                  <p className="text-xl font-black text-white font-mono">{formatMinutes(stats.pureWorkMinutes)}</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Využitie kapacity</p>
                  <p className={`text-4xl font-black font-mono leading-none ${stats.utilizationPercent > 85 ? 'text-emerald-400' : 'text-white'}`}>{stats.utilizationPercent.toFixed(1)}%</p>
                </div>
              </div>

              <div className="bg-slate-950/40 p-4 rounded-xl border border-white/5 flex justify-between items-center">
                <span className="text-[10px] font-black text-teal-500 uppercase tracking-widest">Efektívny čas (+15% réžia):</span>
                <span className="text-xl font-black text-white font-mono">{formatMinutes(stats.effectiveWorkMinutes)}</span>
              </div>

              <div className="w-full bg-slate-950 h-3 rounded-full overflow-hidden shadow-inner border border-white/5">
                <div 
                  style={{ width: `${Math.min(stats.utilizationPercent, 100)}%` }} 
                  className={`h-full transition-all duration-1000 ${getUtilBarColor(stats.utilizationPercent)}`}
                ></div>
              </div>

              <div className="bg-slate-950/60 p-4 rounded-2xl border border-white/10 flex justify-between items-center shadow-inner">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  OČAKÁVANÝ FOND ({stats.numDays} {stats.numDays === 1 ? 'DEŇ' : 'DNI'}):
                </p>
                <p className="text-2xl font-black text-teal-500 font-mono leading-none">
                  {stats.totalAvailableMinutes} <span className="text-xs font-bold text-slate-600 font-sans">MIN</span>
                </p>
              </div>
            </div>
          </div>

          <div className={`${cardStyle} border-t-teal-500`}>
            <h3 className="text-xs font-black text-teal-400 uppercase tracking-[0.2em] mb-8 border-b border-white/5 pb-4">VÝKONOVÉ UKAZOVATELE</h3>
            <div className="grid grid-cols-3 gap-6">
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">LOAD SCORE</p>
                <p className="text-2xl font-black text-teal-400 font-mono">{stats.totalLoad.toFixed(1)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">HOTOVÉ ÚLOHY</p>
                <p className="text-2xl font-black text-white font-mono">{tasks.length}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">PRIEM. REAKCIA</p>
                <p className="text-2xl font-black text-blue-400 font-mono">{Math.round(stats.avgReactionSeconds)}s</p>
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">PLNENIE NORMY</p>
                <p className="text-2xl font-black text-white font-mono">{stats.performanceRatio > 0 ? stats.performanceRatio.toFixed(0) : '---'}%</p>
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{t('pallets')}</p>
                <p className="text-2xl font-black text-white font-mono">{stats.palCount.toFixed(1)}</p>
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">KUSY</p>
                <p className="text-2xl font-black text-white font-mono">{stats.pcsTasks}</p>
              </div>
              <div className="col-span-3 pt-4 border-t border-white/5 flex justify-between items-center">
                <span className="text-[10px] font-black text-slate-500 uppercase">Aktívny čas na úlohách:</span>
                <span className="text-xl font-black text-teal-400 font-mono">{formatDuration(stats.totalExecMs)}</span>
              </div>
            </div>
          </div>

          <div className={`${cardStyle} border-t-sky-500`}>
             <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-4">
               <h3 className="text-xs font-black text-sky-400 uppercase tracking-[0.2em]">LOGISTICKÉ KM</h3>
               <div className="text-right">
                  <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Pomer plných jázd</p>
                  <p className={`text-2xl font-black font-mono ${stats.logEfficiency > 70 ? 'text-green-400' : 'text-amber-400'}`}>{stats.logEfficiency.toFixed(0)}%</p>
               </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-900/30 p-4 rounded-2xl border border-white/5">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1 flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-sky-500"></span> REÁLNA LOGISTIKA
                  </p>
                  <p className="text-2xl font-black text-white font-mono">{stats.totalFullDist.toFixed(1)} <span className="text-xs font-bold text-slate-500">m</span></p>
                </div>
                <div className="bg-slate-900/30 p-4 rounded-2xl border border-white/5">
                  <p className="text-[9px] font-black text-slate-500 uppercase mb-1 flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-red-500/50"></span> JALOVÉ JAZDY
                  </p>
                  <p className="text-2xl font-black text-slate-400 font-mono">{stats.totalEmptyDist.toFixed(1)} <span className="text-xs font-bold text-slate-500">m</span></p>
                </div>
            </div>
            {stats.multiLoadBonus > 0 && (
                <div className="mt-3 bg-teal-500/10 border border-teal-500/30 p-2 rounded-lg flex justify-between items-center">
                    <span className="text-[10px] font-black text-teal-400 uppercase tracking-widest">MULTI-LOAD EFEKTIVITA</span>
                    <span className="text-xs font-black text-teal-400 font-mono">+{stats.multiLoadBonus.toFixed(1)} b</span>
                </div>
            )}
            <p className="mt-4 text-[9px] text-slate-600 italic leading-tight">* Validované Anti-Cheat oknom 45s. Hromadné potvrdenia tej istej trasy sú zlúčené do jednej jazdy.</p>
          </div>

