                        onAddMapSector(newSectorName.toUpperCase(), parseInt(newSectorX), parseInt(newSectorY), newSectorColor); 
                        setNewSectorName(''); setNewSectorX(''); setNewSectorY(''); setNewSectorColor('slate');
