  id: string;
  value: string;
  standardTime?: number;
  description?: string;
  coordX?: number;
  coordY?: number;
  distancePx?: number;
}

export interface MapSector {
  id: string;
  name: string;
  coordX: number;
  coordY: number;
  color?: string;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean; 
  blockedBy?: string | null; 
  isManualBlocked?: boolean; 
  inventoryHistory?: InventorySession[];
  isLogistics?: boolean; 
  isProduction?: boolean;
  isAuditInProgress?: boolean;
  auditBy?: string | null;
  auditFinalBadge?: string | null;
  auditedBy?: string | null;
  auditedAt?: number | null;
  auditResult?: 'OK' | 'NOK' | null;
  auditNote?: string | null;
  expireAt?: number;
  searchExhausted?: boolean;
  searchedBy?: string | null;
  pickedFromSectorId?: string;
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    targetUser: string; 
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
