                  </div>
                  <div className="flex items-center gap-1">
                    <span className="text-[9px] text-slate-600 font-bold uppercase">X:</span>
                    <input 
                      type="number" 
                      value={w.coordX || 0} 
                      onChange={(e) => onUpdateWorkplace(w.id, { coordX: parseInt(e.target.value) || 0 })}
